# Utility module that works with shapes

from shapes import Shape, Rectangle

class ShapeAnalyzer:
    """Analyzes collections of shapes"""

    def total_area(self, shapes: list[Shape]) -> float:
        """Calculate total area of all shapes"""
        total: float = 0.0
        for shape in shapes:
            total = total + shape.area()
        return total

    def count_rectangles(self, shapes: list[Shape]) -> int:
        """Count how many shapes are rectangles"""
        count: int = 0
        for shape in shapes:
            result: bool = isinstance(shape, Rectangle)
            if result:
                count = count + 1
        return count

    def largest_shape(self, shapes: list[Shape]) -> Shape:
        """Find shape with largest area"""
        if len(shapes) == 0:
            raise ValueError("Empty shape list")
        largest: Shape = shapes[0]
        i: int = 1
        while i < len(shapes):
            if shapes[i].area() > largest.area():
                largest = shapes[i]
            i = i + 1
        return largest
